BEGIN
  DELETE FROM crm.client WHERE id = (p_data->>'id')::int;
  RETURN pgv.toast(pgv.t('crm.toast_client_deleted'))
      || pgv.redirect(pgv.call_ref('get_index'));
END;
$function$;
COMMENT ON FUNCTION crm.post_client_delete(jsonb) IS 'Delete a client and cascade contacts + interactions (i18n)';

CREATE OR REPLACE FUNCTION crm.post_client_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_tags text[];
  v_name text;
BEGIN
  v_name := trim(p_data->>'name');
  IF v_name IS NULL OR v_name = '' THEN
    RETURN pgv.toast(pgv.t('crm.err_name_required'), 'error');
  END IF;

  IF p_data->>'tags' IS NOT NULL AND trim(p_data->>'tags') <> '' THEN
    SELECT array_agg(DISTINCT lower(trim(t)))
      INTO v_tags
      FROM unnest(string_to_array(p_data->>'tags', ',')) AS t
     WHERE trim(t) <> '';
  ELSE
    v_tags := '{}';
  END IF;

  IF p_data->>'id' IS NOT NULL AND p_data->>'id' <> '' THEN
    v_id := (p_data->>'id')::int;
    UPDATE crm.client SET
      type = COALESCE(p_data->>'type', type),
      name = v_name,
      email = NULLIF(trim(p_data->>'email'), ''),
      phone = NULLIF(trim(p_data->>'phone'), ''),
      address = NULLIF(trim(p_data->>'address'), ''),
      city = NULLIF(trim(p_data->>'city'), ''),
      postal_code = NULLIF(trim(p_data->>'postal_code'), ''),
      tier = COALESCE(NULLIF(p_data->>'tier', ''), tier),
      tags = v_tags,
      notes = COALESCE(p_data->>'notes', ''),
      active = COALESCE((p_data->>'active')::boolean, active)
    WHERE id = v_id;

    RETURN pgv.toast(pgv.t('crm.toast_client_saved'))
        || pgv.redirect(pgv.call_ref('get_client', jsonb_build_object('p_id', v_id)));
  ELSE
    INSERT INTO crm.client (type, name, email, phone, address, city, postal_code, tier, tags, notes)
    VALUES (
      COALESCE(p_data->>'type', 'individual'),
      v_name,
      NULLIF(trim(p_data->>'email'), ''),
      NULLIF(trim(p_data->>'phone'), ''),
      NULLIF(trim(p_data->>'address'), ''),
      NULLIF(trim(p_data->>'city'), ''),
      NULLIF(trim(p_data->>'postal_code'), ''),
      COALESCE(NULLIF(p_data->>'tier', ''), 'standard'),
      v_tags,
      COALESCE(p_data->>'notes', '')
    ) RETURNING id INTO v_id;

    RETURN pgv.toast(pgv.t('crm.toast_client_created'))
        || pgv.redirect(pgv.call_ref('get_client', jsonb_build_object('p_id', v_id)));
  END IF;
END;
$function$;
COMMENT ON FUNCTION crm.post_client_save(jsonb) IS 'Upsert client — insert or update based on id presence in jsonb (i18n)';

CREATE OR REPLACE FUNCTION crm.post_contact_add(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client_id int := (p_data->>'client_id')::int;
BEGIN
  IF trim(COALESCE(p_data->>'name', '')) = '' THEN
    RETURN pgv.toast(pgv.t('crm.err_name_required'), 'error');
  END IF;

  INSERT INTO crm.contact (client_id, name, role, email, phone, is_primary)
  VALUES (
    v_client_id,
    trim(p_data->>'name'),
    COALESCE(p_data->>'role', ''),
    NULLIF(trim(p_data->>'email'), ''),
    NULLIF(trim(p_data->>'phone'), ''),
    COALESCE((p_data->>'is_primary')::boolean, false)
  );

  RETURN pgv.toast(pgv.t('crm.toast_contact_added'))
      || pgv.redirect(pgv.call_ref('get_client', jsonb_build_object('p_id', v_client_id)));
END;
$function$;
COMMENT ON FUNCTION crm.post_contact_add(jsonb) IS 'Add a secondary contact to a client (i18n)';

CREATE OR REPLACE FUNCTION crm.post_contact_delete(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client_id int;
BEGIN
  SELECT client_id INTO v_client_id FROM crm.contact WHERE id = (p_data->>'id')::int;
  DELETE FROM crm.contact WHERE id = (p_data->>'id')::int;

  RETURN pgv.toast(pgv.t('crm.toast_contact_deleted'))
      || pgv.redirect(pgv.call_ref('get_client', jsonb_build_object('p_id', v_client_id)));
END;
$function$;
COMMENT ON FUNCTION crm.post_contact_delete(jsonb) IS 'Delete a secondary contact (i18n)';

CREATE OR REPLACE FUNCTION crm.post_import_csv(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_csv text;
  v_lines text[];
  v_cols text[];
  v_line text;
  v_imported int := 0;
  v_skipped int := 0;
  v_errors text := '';
  v_name text;
  v_type text;
  i int;
BEGIN
  v_csv := trim(COALESCE(p_data->>'csv', ''));
  IF v_csv = '' THEN
    RETURN pgv.toast(pgv.t('crm.err_no_csv'), 'error');
  END IF;

  v_lines := string_to_array(v_csv, E'\n');

  -- Skip header if it looks like one
  i := 1;
  IF lower(v_lines[1]) LIKE '%nom%' THEN
    i := 2;
  END IF;

  WHILE i <= array_length(v_lines, 1) LOOP
    v_line := trim(v_lines[i]);
    i := i + 1;

    IF v_line = '' THEN CONTINUE; END IF;

    -- Parse CSV line (simple split on ; or ,)
    IF position(';' IN v_line) > 0 THEN
      v_cols := string_to_array(v_line, ';');
    ELSE
      v_cols := string_to_array(v_line, ',');
    END IF;

    -- Columns: nom, email, telephone, adresse, ville, code_postal, type
    v_name := trim(COALESCE(v_cols[1], ''));
    IF v_name = '' THEN
      v_skipped := v_skipped + 1;
      v_errors := v_errors || 'Ligne ' || (i - 1) || ': nom vide. ';
      CONTINUE;
    END IF;

    v_type := lower(trim(COALESCE(v_cols[7], '')));
    IF v_type NOT IN ('individual', 'company') THEN
      v_type := 'individual';
    END IF;

    INSERT INTO crm.client (name, email, phone, address, city, postal_code, type)
    VALUES (
      v_name,
      NULLIF(trim(COALESCE(v_cols[2], '')), ''),
      NULLIF(trim(COALESCE(v_cols[3], '')), ''),
      NULLIF(trim(COALESCE(v_cols[4], '')), ''),
      NULLIF(trim(COALESCE(v_cols[5], '')), ''),
      NULLIF(trim(COALESCE(v_cols[6], '')), ''),
      v_type
    );
    v_imported := v_imported + 1;
  END LOOP;

  IF v_imported = 0 THEN
    RETURN pgv.toast(
      pgv.t('crm.err_no_import') || CASE WHEN v_skipped > 0 THEN ' ' || v_skipped || ' ligne(s) ignorée(s).' ELSE '' END,
      'error');
  END IF;

  RETURN pgv.toast(
      v_imported || ' client(s) importé(s).' || CASE WHEN v_skipped > 0 THEN ' ' || v_skipped || ' ignoré(s).' ELSE '' END)
    || pgv.redirect(pgv.call_ref('get_index'));
END;
$function$;
COMMENT ON FUNCTION crm.post_import_csv(jsonb) IS 'Import clients from CSV text (i18n)';

CREATE OR REPLACE FUNCTION crm.post_interaction_add(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
