COMMENT ON FUNCTION crm.post_interaction_add(jsonb) IS 'Add an interaction to a client (i18n)';

CREATE OR REPLACE FUNCTION crm.tier_variant(p_tier text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE p_tier
    WHEN 'vip' THEN 'warning'
    WHEN 'premium' THEN 'primary'
    ELSE 'default'
  END;
$function$;
COMMENT ON FUNCTION crm.tier_variant(text) IS 'Map client tier to pgv.badge variant';

CREATE OR REPLACE FUNCTION crm.get_index(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_q text;
  v_type text;
  v_tier text;
  v_active text;
  v_total int;
  v_new_month int;
  v_interactions_week int;
  v_rows text[];
  v_body text;
  v_city text;
  r record;
BEGIN
  -- Extract filters
  v_q := NULLIF(trim(COALESCE(p_params->>'q', '')), '');
  v_type := NULLIF(trim(COALESCE(p_params->>'type', '')), '');
  v_tier := NULLIF(trim(COALESCE(p_params->>'tier', '')), '');
  v_active := NULLIF(trim(COALESCE(p_params->>'active', '')), '');
  v_city := NULLIF(trim(COALESCE(p_params->>'city', '')), '');

  -- Stats (unfiltered)
  SELECT count(*)::int INTO v_total FROM crm.client;
  SELECT count(*)::int INTO v_new_month FROM crm.client WHERE created_at >= date_trunc('month', now());
  SELECT count(*)::int INTO v_interactions_week FROM crm.interaction WHERE created_at >= date_trunc('week', now());

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('crm.stat_total_clients'), v_total::text),
    pgv.stat(pgv.t('crm.stat_new_month'), v_new_month::text),
    pgv.stat(pgv.t('crm.stat_interactions_week'), v_interactions_week::text)
  ]);

  -- Search/filter form
  v_body := v_body
    || '<form>'
    || '<div class="grid">'
    || pgv.input('q', 'search', pgv.t('crm.field_search_name_email'), v_q)
    || pgv.sel('type', pgv.t('crm.field_type'), jsonb_build_array(
         jsonb_build_object('label', pgv.t('crm.filter_all'), 'value', ''),
         jsonb_build_object('label', pgv.t('crm.type_individual'), 'value', 'individual'),
         jsonb_build_object('label', pgv.t('crm.type_company'), 'value', 'company')
       ), COALESCE(v_type, ''))
    || pgv.sel('tier', pgv.t('crm.field_tier'), jsonb_build_array(
         jsonb_build_object('label', pgv.t('crm.filter_all'), 'value', ''),
         jsonb_build_object('label', 'Standard', 'value', 'standard'),
         jsonb_build_object('label', 'Premium', 'value', 'premium'),
         jsonb_build_object('label', 'VIP', 'value', 'vip')
       ), COALESCE(v_tier, ''))
    || pgv.sel('active', pgv.t('crm.field_active'), jsonb_build_array(
         jsonb_build_object('label', pgv.t('crm.filter_all'), 'value', ''),
         jsonb_build_object('label', pgv.t('crm.yes'), 'value', 'true'),
         jsonb_build_object('label', pgv.t('crm.no'), 'value', 'false')
       ), COALESCE(v_active, ''))
    || pgv.input('city', 'text', pgv.t('crm.field_city'), v_city)
    || '</div>'
    || '<button type="submit" class="secondary">' || pgv.t('crm.btn_filter') || '</button>'
    || '</form>';

  -- Client list with filters
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT c.id, c.name, crm.type_label(c.type) AS type_label,
           c.city, c.tier, c.active,
           (SELECT count(*) FROM crm.interaction i WHERE i.client_id = c.id) AS nb_interactions
      FROM crm.client c
     WHERE (v_q IS NULL OR c.name ILIKE '%' || v_q || '%' OR c.email ILIKE '%' || v_q || '%')
       AND (v_type IS NULL OR c.type = v_type)
       AND (v_tier IS NULL OR c.tier = v_tier)
       AND (v_active IS NULL OR c.active = (v_active = 'true'))
       AND (v_city IS NULL OR c.city ILIKE '%' || v_city || '%')
     ORDER BY c.updated_at DESC
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_client', jsonb_build_object('p_id', r.id)), pgv.esc(r.name)),
      r.type_label,
      COALESCE(r.city, '—'),
      pgv.badge(upper(r.tier), crm.tier_variant(r.tier)),
      r.nb_interactions::text,
      CASE WHEN r.active THEN pgv.t('crm.yes') ELSE pgv.t('crm.no') END
    ];
  END LOOP;

  IF v_total = 0 THEN
    v_body := v_body || pgv.empty(pgv.t('crm.empty_no_client'), pgv.t('crm.empty_first_client'));
  ELSIF cardinality(v_rows) = 0 THEN
    v_body := v_body || pgv.empty(pgv.t('crm.empty_no_results'));
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY[pgv.t('crm.col_client'), pgv.t('crm.col_type'), pgv.t('crm.col_city'), pgv.t('crm.col_tier'), pgv.t('crm.col_interactions'), pgv.t('crm.col_active')],
      v_rows,
      20
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">%s</a> <a href="%s" role="button" class="secondary">%s</a></p>',
    pgv.call_ref('get_client_form'), pgv.t('crm.btn_new_client'),
    pgv.call_ref('get_import'), pgv.t('crm.btn_import_csv'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION crm.get_index(jsonb) IS 'CRM dashboard — stats, search/filters, client list (i18n)';

CREATE OR REPLACE FUNCTION crm.type_label(p_type text)
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  SELECT CASE p_type
    WHEN 'individual' THEN pgv.t('crm.type_individual')
    WHEN 'company' THEN pgv.t('crm.type_company')
    WHEN 'call' THEN pgv.t('crm.type_call')
    WHEN 'visit' THEN pgv.t('crm.type_visit')
    WHEN 'email' THEN pgv.t('crm.type_email')
    WHEN 'note' THEN pgv.t('crm.type_note')
    ELSE p_type
  END;
$function$;
COMMENT ON FUNCTION crm.type_label(text) IS 'Translate type codes to localized labels via i18n';

CREATE OR REPLACE FUNCTION crm.get_client(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client crm.client;
  v_fiche text;
  v_contacts text;
  v_interactions text;
  v_tab_fiche text;
  v_tab_interactions text;
  v_body text;
  r record;
  v_activity text;
  v_rows text;
  v_timeline jsonb;
  v_stats text;
  v_n int;
  v_ca numeric;
BEGIN
  SELECT * INTO v_client FROM crm.client WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN pgv.alert(pgv.t('crm.err_not_found'), 'danger');
  END IF;

  v_fiche := pgv.dl(VARIADIC ARRAY[
    pgv.t('crm.field_type'), crm.type_label(v_client.type),
    pgv.t('crm.field_email'), COALESCE(v_client.email, '—'),
    pgv.t('crm.field_phone'), COALESCE(v_client.phone, '—'),
    pgv.t('crm.field_address'), COALESCE(v_client.address, '—'),
    pgv.t('crm.field_city'), COALESCE(v_client.city, '—'),
    pgv.t('crm.field_postal_code'), COALESCE(v_client.postal_code, '—'),
    pgv.t('crm.field_tier'), pgv.badge(upper(v_client.tier), crm.tier_variant(v_client.tier)),
    pgv.t('crm.field_active'), CASE WHEN v_client.active THEN pgv.t('crm.yes') ELSE pgv.t('crm.no') END,
    pgv.t('crm.field_notes'), CASE WHEN v_client.notes = '' THEN '—' ELSE pgv.esc(v_client.notes) END
  ]);

  IF array_length(v_client.tags, 1) > 0 THEN
    v_fiche := v_fiche || '<p>';
    FOR i IN 1..array_length(v_client.tags, 1) LOOP
      v_fiche := v_fiche || pgv.badge(v_client.tags[i], 'default') || ' ';
    END LOOP;
    v_fiche := v_fiche || '</p>';
  END IF;

  v_contacts := '';
  FOR r IN SELECT * FROM crm.contact WHERE client_id = p_id ORDER BY is_primary DESC, name LOOP
    v_contacts := v_contacts || pgv.card(
      pgv.esc(r.name) || CASE WHEN r.is_primary THEN ' ' || pgv.badge(pgv.t('crm.badge_primary'), 'primary') ELSE '' END,
      pgv.dl(VARIADIC ARRAY[
        pgv.t('crm.field_role'), CASE WHEN r.role = '' THEN '—' ELSE pgv.esc(r.role) END,
        pgv.t('crm.field_email'), COALESCE(r.email, '—'),
        pgv.t('crm.field_phone'), COALESCE(r.phone, '—')
      ]),
      pgv.action('post_contact_delete', pgv.t('crm.btn_delete'), jsonb_build_object('id', r.id), pgv.t('crm.confirm_delete_contact'), 'danger')
    );
  END LOOP;

  IF v_contacts = '' THEN
    v_contacts := pgv.empty(pgv.t('crm.empty_no_contacts'));
  END IF;

  v_contacts := v_contacts || pgv.accordion(VARIADIC ARRAY[
    pgv.t('crm.title_add_contact'),
    pgv.form('post_contact_add',
      '<input type="hidden" name="client_id" value="' || p_id || '">'
      || pgv.input('name', 'text', pgv.t('crm.field_name'), NULL, true)
      || pgv.input('role', 'text', pgv.t('crm.field_role'))
      || pgv.input('email', 'email', pgv.t('crm.field_email'))
      || pgv.input('phone', 'tel', pgv.t('crm.field_phone'))
      || pgv.checkbox('is_primary', pgv.t('crm.label_primary_contact')),
      pgv.t('crm.btn_add'))
  ]);

  v_tab_fiche := v_fiche || '<hr>' || '<h4>' || pgv.t('crm.title_contacts') || '</h4>' || v_contacts;

  -- Activité liée (cross-module)
  v_activity := '';
  v_stats := '';

  BEGIN
    EXECUTE 'SELECT count(*) FROM quote.devis WHERE client_id = $1' INTO v_n USING p_id;
    IF v_n > 0 THEN v_stats := v_stats || pgv.stat(pgv.t('crm.cross_quotes'), v_n::text); END IF;
  EXCEPTION WHEN undefined_table OR invalid_schema_name THEN NULL;
  END;

  BEGIN
    EXECUTE '
      SELECT count(DISTINCT f.id),
             coalesce(sum(l.quantite * l.prix_unitaire * (1 + l.tva_rate / 100)), 0)
      FROM quote.facture f
      LEFT JOIN quote.ligne l ON l.facture_id = f.id
      WHERE f.client_id = $1'
    INTO v_n, v_ca USING p_id;
    IF v_n > 0 THEN
      v_stats := v_stats || pgv.stat(pgv.t('crm.cross_invoices'), v_n::text);
      v_stats := v_stats || pgv.stat(pgv.t('crm.cross_revenue'), to_char(v_ca, 'FM999G999G990D00') || E' \u20ac');
    END IF;
  EXCEPTION WHEN undefined_table OR invalid_schema_name THEN NULL;
  END;

  BEGIN
    EXECUTE 'SELECT count(*) FROM project.chantier WHERE client_id = $1' INTO v_n USING p_id;
    IF v_n > 0 THEN v_stats := v_stats || pgv.stat(pgv.t('crm.cross_projects'), v_n::text); END IF;
  EXCEPTION WHEN undefined_table OR invalid_schema_name THEN NULL;
  END;

  IF v_stats <> '' THEN
    v_activity := pgv.grid(v_stats) || v_activity;
  END IF;

  BEGIN
    v_rows := '';
    FOR r IN EXECUTE 'SELECT id, numero, statut FROM quote.devis WHERE client_id = $1 ORDER BY id DESC' USING p_id LOOP
      v_rows := v_rows || '| ' || pgv.esc(r.numero::text) || ' | ' || pgv.esc(r.statut::text) || ' | [' || pgv.t('crm.cross_see') || '](/' || 'quote/devis?p_id=' || r.id || ') |' || E'\n';
    END LOOP;
    IF v_rows <> '' THEN
      v_activity := v_activity || '<h4>' || pgv.t('crm.cross_quotes') || '</h4><md>' || E'\n' || '| ' || pgv.t('crm.col_number') || ' | ' || pgv.t('crm.col_status') || ' | |' || E'\n' || '|--------|--------|-|' || E'\n' || v_rows || '</md>';
    END IF;
  EXCEPTION WHEN undefined_table OR invalid_schema_name THEN NULL;
  END;

  BEGIN
    v_rows := '';
    FOR r IN EXECUTE 'SELECT id, numero, statut FROM project.chantier WHERE client_id = $1 ORDER BY id DESC' USING p_id LOOP
      v_rows := v_rows || '| ' || pgv.esc(r.numero::text) || ' | ' || pgv.esc(r.statut::text) || ' | [' || pgv.t('crm.cross_see') || '](/' || 'project/chantier?p_id=' || r.id || ') |' || E'\n';
    END LOOP;
    IF v_rows <> '' THEN
      v_activity := v_activity || '<h4>' || pgv.t('crm.cross_projects') || '</h4><md>' || E'\n' || '| ' || pgv.t('crm.col_number') || ' | ' || pgv.t('crm.col_status') || ' | |' || E'\n' || '|--------|--------|-|' || E'\n' || v_rows || '</md>';
    END IF;
  EXCEPTION WHEN undefined_table OR invalid_schema_name THEN NULL;
  END;

  BEGIN
    v_rows := '';
    FOR r IN EXECUTE 'SELECT id, numero, statut FROM purchase.commande WHERE fournisseur_id = $1 ORDER BY id DESC' USING p_id LOOP
      v_rows := v_rows || '| ' || pgv.esc(r.numero::text) || ' | ' || pgv.esc(r.statut::text) || ' | [' || pgv.t('crm.cross_see') || '](/' || 'purchase/commande?p_id=' || r.id || ') |' || E'\n';
    END LOOP;
    IF v_rows <> '' THEN
      v_activity := v_activity || '<h4>' || pgv.t('crm.cross_purchase_orders') || '</h4><md>' || E'\n' || '| ' || pgv.t('crm.col_number') || ' | ' || pgv.t('crm.col_status') || ' | |' || E'\n' || '|--------|--------|-|' || E'\n' || v_rows || '</md>';
    END IF;
  EXCEPTION WHEN undefined_table OR invalid_schema_name THEN NULL;
  END;

  IF v_activity <> '' THEN
    v_tab_fiche := v_tab_fiche || '<hr><h4>' || pgv.t('crm.title_activity') || '</h4>' || v_activity;
  END IF;

  v_tab_fiche := v_tab_fiche || '<hr>'
    || format('<a href="%s" role="button">%s</a> ', pgv.call_ref('get_client_form', jsonb_build_object('p_id', p_id)), pgv.t('crm.btn_edit'))
    || pgv.action('post_client_delete', pgv.t('crm.btn_delete'), jsonb_build_object('id', p_id), pgv.t('crm.confirm_delete_client'), 'danger');

  -- Timeline (CRM interactions + cross-module)
  v_timeline := '[]'::jsonb;

  FOR r IN SELECT type, subject, body, created_at FROM crm.interaction WHERE client_id = p_id LOOP
    v_timeline := v_timeline || jsonb_build_object(
      'dt', r.created_at, 'badge', crm.type_label(r.type),
      'variant', CASE r.type WHEN 'call' THEN 'primary' WHEN 'visit' THEN 'success' ELSE 'default' END,
      'title', r.subject, 'detail', r.body, 'link', '');
  END LOOP;

  BEGIN
    FOR r IN EXECUTE 'SELECT numero, statut, created_at, id FROM quote.devis WHERE client_id = $1' USING p_id LOOP
      v_timeline := v_timeline || jsonb_build_object(
        'dt', r.created_at, 'badge', pgv.t('crm.cross_quotes'), 'variant', 'warning',
        'title', r.numero::text || E' \u2014 ' || r.statut::text, 'detail', '',
        'link', '/quote/devis?p_id=' || r.id);
    END LOOP;
  EXCEPTION WHEN undefined_table OR invalid_schema_name THEN NULL;
  END;

  BEGIN
    FOR r IN EXECUTE 'SELECT numero, statut, created_at, id FROM quote.facture WHERE client_id = $1' USING p_id LOOP
      v_timeline := v_timeline || jsonb_build_object(
        'dt', r.created_at, 'badge', pgv.t('crm.cross_invoices'), 'variant', 'danger',
        'title', r.numero::text || E' \u2014 ' || r.statut::text, 'detail', '',
        'link', '/quote/facture?p_id=' || r.id);
    END LOOP;
  EXCEPTION WHEN undefined_table OR invalid_schema_name THEN NULL;
  END;

  BEGIN
    FOR r IN EXECUTE 'SELECT numero, statut, created_at, id FROM project.chantier WHERE client_id = $1' USING p_id LOOP
      v_timeline := v_timeline || jsonb_build_object(
        'dt', r.created_at, 'badge', pgv.t('crm.cross_projects'), 'variant', 'primary',
        'title', r.numero::text || E' \u2014 ' || r.statut::text, 'detail', '',
        'link', '/project/chantier?p_id=' || r.id);
    END LOOP;
  EXCEPTION WHEN undefined_table OR invalid_schema_name THEN NULL;
  END;

  IF jsonb_array_length(v_timeline) = 0 THEN
    v_interactions := pgv.empty(pgv.t('crm.empty_no_events'));
  ELSE
    v_interactions := pgv.timeline((
      SELECT jsonb_agg(
        jsonb_build_object(
          'date', to_char((e->>'dt')::timestamptz, 'DD/MM/YYYY HH24:MI'),
          'label', (e->>'badge') || E' \u2014 ' || (e->>'title'),
          'detail', nullif(e->>'detail', ''),
          'badge', e->>'variant'
        ) ORDER BY (e->>'dt')::timestamptz DESC
      )
      FROM jsonb_array_elements(v_timeline) AS e
    ));
  END IF;

  v_interactions := v_interactions || pgv.accordion(VARIADIC ARRAY[
    pgv.t('crm.title_add_interaction'),
    pgv.form('post_interaction_add',
      '<input type="hidden" name="client_id" value="' || p_id || '">'
      || pgv.sel('type', pgv.t('crm.field_type'), jsonb_build_array(
           jsonb_build_object('label', pgv.t('crm.type_call'), 'value', 'call'),
           jsonb_build_object('label', pgv.t('crm.type_visit'), 'value', 'visit'),
           jsonb_build_object('label', pgv.t('crm.type_email'), 'value', 'email'),
           jsonb_build_object('label', pgv.t('crm.type_note'), 'value', 'note')
         ), 'note')
      || pgv.input('subject', 'text', pgv.t('crm.field_subject'), NULL, true)
      || pgv.textarea('body', pgv.t('crm.field_details')),
      pgv.t('crm.btn_add'))
  ]);

  v_tab_interactions := v_interactions;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[pgv.t('crm.nav_clients'), pgv.call_ref('get_index'), v_client.name])
    || pgv.tabs(VARIADIC ARRAY[pgv.t('crm.title_fiche'), v_tab_fiche, pgv.t('crm.title_timeline'), v_tab_interactions]);

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION crm.get_client(integer) IS 'Client detail page — breadcrumb, tabs, contacts, cross-module activity (i18n)';

CREATE OR REPLACE FUNCTION crm.get_interactions(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_q text;
  v_type text;
  v_period text;
  v_total int;
  v_tl jsonb;
  v_body text;
  v_date_from timestamptz;
  r record;
BEGIN
  v_q := NULLIF(trim(COALESCE(p_params->>'q', '')), '');
  v_type := NULLIF(trim(COALESCE(p_params->>'type', '')), '');
  v_period := NULLIF(trim(COALESCE(p_params->>'period', '')), '');

  -- Period filter
  IF v_period = 'week' THEN
    v_date_from := date_trunc('week', now());
  ELSIF v_period = 'month' THEN
    v_date_from := date_trunc('month', now());
  ELSIF v_period = '3months' THEN
    v_date_from := now() - interval '3 months';
  END IF;

  SELECT count(*)::int INTO v_total FROM crm.interaction;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('crm.stat_total_interactions'), v_total::text)
  ]);

  -- Filters
  v_body := v_body
    || '<form>'
    || '<div class="grid">'
    || pgv.input('q', 'search', pgv.t('crm.field_search_subject'), v_q)
    || pgv.sel('type', pgv.t('crm.field_type'), jsonb_build_array(
         jsonb_build_object('label', pgv.t('crm.filter_all'), 'value', ''),
         jsonb_build_object('label', pgv.t('crm.type_call'), 'value', 'call'),
         jsonb_build_object('label', pgv.t('crm.type_visit'), 'value', 'visit'),
         jsonb_build_object('label', pgv.t('crm.type_email'), 'value', 'email'),
         jsonb_build_object('label', pgv.t('crm.type_note'), 'value', 'note')
       ), COALESCE(v_type, ''))
    || pgv.sel('period', pgv.t('crm.field_period'), jsonb_build_array(
         jsonb_build_object('label', pgv.t('crm.filter_all_f'), 'value', ''),
         jsonb_build_object('label', pgv.t('crm.period_week'), 'value', 'week'),
         jsonb_build_object('label', pgv.t('crm.period_month'), 'value', 'month'),
         jsonb_build_object('label', pgv.t('crm.period_3months'), 'value', '3months')
       ), COALESCE(v_period, ''))
    || '</div>'
    || '<button type="submit" class="secondary">' || pgv.t('crm.btn_filter') || '</button>'
    || '</form>';

  v_tl := '[]'::jsonb;
  FOR r IN
    SELECT i.type, i.subject, i.created_at, c.name AS client_name
      FROM crm.interaction i
      JOIN crm.client c ON c.id = i.client_id
     WHERE (v_q IS NULL OR i.subject ILIKE '%' || v_q || '%')
       AND (v_type IS NULL OR i.type = v_type)
       AND (v_date_from IS NULL OR i.created_at >= v_date_from)
     ORDER BY i.created_at DESC
  LOOP
    v_tl := v_tl || jsonb_build_object(
      'date', to_char(r.created_at, 'DD/MM/YYYY HH24:MI'),
      'label', crm.type_label(r.type) || E' \u2014 ' || r.subject,
      'detail', r.client_name,
      'badge', CASE r.type WHEN 'call' THEN 'primary' WHEN 'visit' THEN 'success' ELSE 'info' END
    );
  END LOOP;

  IF jsonb_array_length(v_tl) = 0 AND v_total = 0 THEN
    v_body := v_body || pgv.empty(pgv.t('crm.empty_no_interaction'));
  ELSIF jsonb_array_length(v_tl) = 0 THEN
    v_body := v_body || pgv.empty(pgv.t('crm.empty_no_results'));
  ELSE
    v_body := v_body || pgv.timeline(v_tl);
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION crm.get_interactions(jsonb) IS 'All interactions page — filters by type, period, subject search (i18n)';

GRANT USAGE ON SCHEMA crm TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA crm TO web_anon;

-- Schema: crm_ut
CREATE SCHEMA IF NOT EXISTS crm_ut;

CREATE OR REPLACE FUNCTION crm_ut.test_client_options()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_row record;
  v_count int;
BEGIN
  -- Setup: insert a test client
  INSERT INTO crm.client (name, type, email, city, active)
  VALUES ('UT_Options_Test', 'individual', 'ut@test.com', 'Grenoble', true)
  RETURNING id INTO v_id;

  -- Test 1: found by name
  SELECT count(*) INTO v_count FROM crm.client_options('UT_Options');
  RETURN NEXT ok(v_count = 1, 'search by name finds client');

  -- Test 2: found by city
  SELECT count(*) INTO v_count FROM crm.client_options('Grenoble');
  RETURN NEXT ok(v_count >= 1, 'search by city finds client');

  -- Test 3: found by email
  SELECT count(*) INTO v_count FROM crm.client_options('ut@test');
  RETURN NEXT ok(v_count = 1, 'search by email finds client');

  -- Test 4: detail format contains city and email
  SELECT * INTO v_row FROM crm.client_options('UT_Options') LIMIT 1;
  RETURN NEXT ok(v_row.value = v_id::text, 'value is client id');
  RETURN NEXT ok(v_row.label = 'UT_Options_Test', 'label is client name');
  RETURN NEXT ok(v_row.detail LIKE '%Grenoble%', 'detail contains city');
  RETURN NEXT ok(v_row.detail LIKE '%ut@test.com%', 'detail contains email');

  -- Test 5: inactive client not returned
  UPDATE crm.client SET active = false WHERE id = v_id;
  SELECT count(*) INTO v_count FROM crm.client_options('UT_Options');
  RETURN NEXT ok(v_count = 0, 'inactive client excluded');

  -- Test 6: NULL search returns results
  SELECT count(*) INTO v_count FROM crm.client_options(NULL);
  RETURN NEXT ok(v_count > 0, 'NULL search returns all active');

  -- Cleanup
  DELETE FROM crm.client WHERE id = v_id;
END;
$function$;
COMMENT ON FUNCTION crm_ut.test_client_options() IS 'Unit test for crm.client_options — search, filtering, detail format';

CREATE OR REPLACE FUNCTION crm_ut.test_display_name()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client crm.client;
BEGIN
  v_client.type := 'individual'; v_client.name := 'Jean Dupont'; v_client.city := 'Lyon';
  RETURN NEXT is(crm.display_name(v_client), 'Jean Dupont', 'individual: name only');

  v_client.type := 'company'; v_client.name := 'ACME'; v_client.city := 'Paris';
  RETURN NEXT is(crm.display_name(v_client), 'ACME (Paris)', 'company with city');

  v_client.type := 'company'; v_client.name := 'ACME'; v_client.city := NULL;
  RETURN NEXT is(crm.display_name(v_client), 'ACME', 'company without city');
END;
$function$;
COMMENT ON FUNCTION crm_ut.test_display_name() IS 'Test display_name helper';

CREATE OR REPLACE FUNCTION crm_ut.test_post_client_delete()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_result text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO crm.client (type, name) VALUES ('individual', 'To Delete') RETURNING id INTO v_id;
  INSERT INTO crm.interaction (client_id, type, subject) VALUES (v_id, 'note', 'Test note');
  INSERT INTO crm.contact (client_id, name) VALUES (v_id, 'Contact Test');

  v_result := crm.post_client_delete(jsonb_build_object('id', v_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'delete returns success');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'delete redirects');
  RETURN NEXT ok(NOT EXISTS(SELECT 1 FROM crm.client WHERE id = v_id), 'client deleted');
  RETURN NEXT ok(NOT EXISTS(SELECT 1 FROM crm.interaction WHERE client_id = v_id), 'interactions cascaded');
  RETURN NEXT ok(NOT EXISTS(SELECT 1 FROM crm.contact WHERE client_id = v_id), 'contacts cascaded');
END;
$function$;
COMMENT ON FUNCTION crm_ut.test_post_client_delete() IS 'Test client delete with cascade';

CREATE OR REPLACE FUNCTION crm_ut.test_post_client_save()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_client crm.client;
  v_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Create
  v_result := crm.post_client_save('{"name":"Test Client","type":"individual","email":"test@example.com","tags":"plomberie, Urgent, plomberie","city":"Lyon"}'::jsonb);
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'create returns success toast');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'create returns redirect');

  SELECT id INTO v_id FROM crm.client WHERE name = 'Test Client';
  SELECT * INTO v_client FROM crm.client WHERE id = v_id;
  RETURN NEXT is(v_client.email, 'test@example.com'::text, 'email saved');
  RETURN NEXT is(v_client.city, 'Lyon'::text, 'city saved');
  RETURN NEXT ok(v_client.tags @> ARRAY['plomberie','urgent'], 'tags normalized and deduplicated');
  RETURN NEXT is(array_length(v_client.tags, 1), 2, 'duplicate tag removed');

  -- Update
  v_result := crm.post_client_save(('{"id":' || v_id || ',"name":"Test Updated","type":"company","tier":"premium"}')::jsonb);
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'update returns success toast');
  SELECT * INTO v_client FROM crm.client WHERE id = v_id;
  RETURN NEXT is(v_client.name, 'Test Updated'::text, 'name updated');
  RETURN NEXT is(v_client.tier, 'premium'::text, 'tier updated');

  -- Validation: empty name
  v_result := crm.post_client_save('{"name":""}'::jsonb);
  RETURN NEXT ok(v_result LIKE '%data-toast="error"%', 'empty name returns error');

  -- Cleanup
  DELETE FROM crm.client WHERE id = v_id;
END;
$function$;
COMMENT ON FUNCTION crm_ut.test_post_client_save() IS 'Test client upsert (create, update, validation)';

CREATE OR REPLACE FUNCTION crm_ut.test_post_contact_add()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client_id int;
  v_result text;
  v_contact crm.contact;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO crm.client (type, name) VALUES ('company', 'Contact Add Test Co') RETURNING id INTO v_client_id;

  -- Validation: empty name
  v_result := crm.post_contact_add(jsonb_build_object('client_id', v_client_id, 'name', ''));
  RETURN NEXT ok(v_result LIKE '%data-toast="error"%', 'empty name returns error');

  -- Nominal: add contact with all fields
  v_result := crm.post_contact_add(jsonb_build_object('client_id', v_client_id, 'name', 'Marie', 'role', 'Directrice', 'email', 'marie@test.com', 'phone', '0601020304', 'is_primary', true));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'add returns success');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'add returns redirect');

  SELECT * INTO v_contact FROM crm.contact WHERE client_id = v_client_id;
  RETURN NEXT is(v_contact.name, 'Marie'::text, 'name saved');
  RETURN NEXT is(v_contact.role, 'Directrice'::text, 'role saved');
  RETURN NEXT is(v_contact.email, 'marie@test.com'::text, 'email saved');
  RETURN NEXT is(v_contact.phone, '0601020304'::text, 'phone saved');
  RETURN NEXT is(v_contact.is_primary, true, 'is_primary saved');

  -- Cleanup
  DELETE FROM crm.client WHERE id = v_client_id;
END;
$function$;
COMMENT ON FUNCTION crm_ut.test_post_contact_add() IS 'Test contact add — nominal + validation';

CREATE OR REPLACE FUNCTION crm_ut.test_post_contact_delete()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client_id int;
  v_contact_id int;
  v_result text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO crm.client (type, name) VALUES ('company', 'Contact Del Test Co') RETURNING id INTO v_client_id;
  INSERT INTO crm.contact (client_id, name, role) VALUES (v_client_id, 'To Delete', 'Test') RETURNING id INTO v_contact_id;

  -- Nominal: delete contact
  v_result := crm.post_contact_delete(jsonb_build_object('id', v_contact_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'delete returns success');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'delete returns redirect');
  RETURN NEXT ok(NOT EXISTS(SELECT 1 FROM crm.contact WHERE id = v_contact_id), 'contact deleted from DB');

  -- Cleanup
  DELETE FROM crm.client WHERE id = v_client_id;
END;
$function$;
COMMENT ON FUNCTION crm_ut.test_post_contact_delete() IS 'Test contact delete — nominal + DB verification';

CREATE OR REPLACE FUNCTION crm_ut.test_post_import_csv()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_count int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Empty CSV
  v_result := crm.post_import_csv('{"csv":""}'::jsonb);
  RETURN NEXT ok(v_result LIKE '%data-toast="error"%', 'empty csv returns error');

  -- Nominal with header + semicolons
  v_result := crm.post_import_csv(('{"csv":"nom;email;telephone;adresse;ville;code_postal;type\nAlice Import;alice@test.com;0600000001;1 rue A;Paris;75001;individual\nBob Import;bob@test.com;0600000002;2 rue B;Lyon;69001;company"}')::jsonb);
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'import returns success');
  RETURN NEXT ok(v_result LIKE '%2 client(s) importé(s)%', 'imported 2 clients');

  SELECT count(*)::int INTO v_count FROM crm.client WHERE name IN ('Alice Import', 'Bob Import');
  RETURN NEXT is(v_count, 2, '2 clients in DB');

  -- Verify fields
  RETURN NEXT ok(EXISTS(SELECT 1 FROM crm.client WHERE name = 'Alice Import' AND email = 'alice@test.com' AND city = 'Paris' AND type = 'individual'), 'Alice fields correct');
  RETURN NEXT ok(EXISTS(SELECT 1 FROM crm.client WHERE name = 'Bob Import' AND type = 'company'), 'Bob type correct');

  -- Line with empty name is skipped
  v_result := crm.post_import_csv('{"csv":";skip@test.com;000\nCharlie Import;charlie@test.com;000"}'::jsonb);
  RETURN NEXT ok(v_result LIKE '%1 client(s) importé(s)%', '1 imported, empty name skipped');
  RETURN NEXT ok(v_result LIKE '%1 ignoré(s)%', '1 skipped reported');

  -- Comma separator
  v_result := crm.post_import_csv('{"csv":"Delta Import,delta@test.com,000,addr,Nice,06000,individual"}'::jsonb);
  RETURN NEXT ok(v_result LIKE '%1 client(s) importé(s)%', 'comma separator works');

  -- Cleanup
  DELETE FROM crm.client WHERE name IN ('Alice Import', 'Bob Import', 'Charlie Import', 'Delta Import');
END;
$function$;
COMMENT ON FUNCTION crm_ut.test_post_import_csv() IS 'Test CSV import — nominal, header skip, empty name, empty CSV';

CREATE OR REPLACE FUNCTION crm_ut.test_post_interaction_add()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_result text;
  v_interaction crm.interaction;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO crm.client (type, name) VALUES ('individual', 'Interaction Test') RETURNING id INTO v_id;

  v_result := crm.post_interaction_add(jsonb_build_object('client_id', v_id, 'type', 'call', 'subject', 'Appel test', 'body', 'Détails'));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'add returns success');

  SELECT * INTO v_interaction FROM crm.interaction WHERE client_id = v_id;
  RETURN NEXT is(v_interaction.type, 'call'::text, 'type saved');
  RETURN NEXT is(v_interaction.subject, 'Appel test'::text, 'subject saved');
  RETURN NEXT is(v_interaction.body, 'Détails'::text, 'body saved');

  -- Validation: empty subject
  v_result := crm.post_interaction_add(jsonb_build_object('client_id', v_id, 'subject', ''));
  RETURN NEXT ok(v_result LIKE '%data-toast="error"%', 'empty subject returns error');

  DELETE FROM crm.client WHERE id = v_id;
END;
$function$;
COMMENT ON FUNCTION crm_ut.test_post_interaction_add() IS 'Test interaction add + validation';

CREATE OR REPLACE FUNCTION crm_ut.test_tier_variant()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT is(crm.tier_variant('vip'), 'warning', 'vip -> warning');
  RETURN NEXT is(crm.tier_variant('premium'), 'primary', 'premium -> primary');
  RETURN NEXT is(crm.tier_variant('standard'), 'default', 'standard -> default');
END;
$function$;
COMMENT ON FUNCTION crm_ut.test_tier_variant() IS 'Test tier_variant helper';

CREATE OR REPLACE FUNCTION crm_ut.test_type_label()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT is(crm.type_label('individual'), 'Particulier', 'individual -> Particulier');
  RETURN NEXT is(crm.type_label('company'), 'Entreprise', 'company -> Entreprise');
  RETURN NEXT is(crm.type_label('call'), 'Appel', 'call -> Appel');
  RETURN NEXT is(crm.type_label('visit'), 'Visite', 'visit -> Visite');
  RETURN NEXT is(crm.type_label('email'), 'Courriel', 'email -> Courriel');
  RETURN NEXT is(crm.type_label('note'), 'Note', 'note -> Note');
END;
$function$;
COMMENT ON FUNCTION crm_ut.test_type_label() IS 'Test type_label helper';

